string dg() { // 解压缩函数
    int k;//压缩的次数
    char ch;//输入的字符
    string s = "", str = "";//s是最终答案，str是被压缩的字串

    //cin >> ch 会跳过空格和换行符
    while (cin.get(ch)) { //用cin.get()读取字符,避免跳过空格和换行
        if (ch == '[') {//如果找到了被压缩的字串
            cin >> k; // 读取压缩次数
            str = dg(); // 递归调用
            while (k--) {
                s += str;//把解压后的字串复制k次后添加到原来的字符串上
            }
        } else if (ch == ']') {//如果找到了压缩的字串的末尾
            return s; // 结束这一层递归并返回已经解压的字符串
        } else {
            s += ch;//直接在最后添上这个字符。
        }
    }

    return s; // 确保函数有返回值
}

