void highadd(int k)//第k阶台阶,高精度加法 
{
    for(int i = 1; i <= len; i ++)
        arr[k][i] = arr[k-1][i] + arr[k-2][i];//第k阶的方法等于一次走一步+一次性走两步的 

    for(int i = 1; i <= len; i ++)
    {
        if(arr[k][i] >= 10)
        {
            arr[k][i+ 1] += arr[k][i] / 10;//进位
            arr[k][i] %= 10;
            if(arr[k][len + 1] != 0) len++;//如果最高位有进位，那么位数➕➕
        }
     } 
 } 

