void recur(int x)//分解x使其表示为2和2(0)的组合
{
    for(int i = 14; i >= 0;i--)
    {
        if(pow(2,i) <= x)
        {
            if(i == 1) cout << "2";//2(1)不用再往后分解了且2^1输出为2,单独出来
            else if(i == 0) cout << "2(0)";//2(0)也不用再往后分解了,单独出来
            else{//指数不是这两种情况则还得分解
                cout <<"2(";
                recur(i);
                cout << ")";
            }
            x -= pow(2,i);
            if(x != 0) cout << "+";//加号处理的最简单方法:若此x还没分解完,则后面还有项,所以输出一个+号

        }
    }
}

