#include <bits/stdc++.h>
using namespace std;

int n, a, b, m;             // m 表示 sum 的有效位最大下标
int p[1010], lp = 0;        // p 存当前最大值结果，高精度整数，lp 是最大下标
int sum[1010];              // sum 存当前乘积，高精度整数
int ans[1010], ls = 0;      // ans 存除法结果临时数组，ls 是最大下标
int res;                    // 除法中保存的余数

struct node {
    int a, b;
    bool operator<(const node &W) const {
        return a * b < W.a * W.b;
    }
} arr[1010];

bool compare() {
    int i = 0, j = 0;
    while (i <= lp && p[i] == 0) i++;  // 去除 p 的前导 0
    while (j <= ls && ans[j] == 0) j++;  // 去除 ans 的前导 0

    int len1 = lp - i + 1;
    int len2 = ls - j + 1;
    if (len1 > len2) return false;
    if (len1 < len2) return true;

    while (i <= lp && j <= ls) {
        if (p[i] < ans[j]) return true;
        if (p[i] > ans[j]) return false;
        i++;
        j++;
    }
    return false;
}

void cheng(int d) {
    for (int i = 0; i <= m; i++) sum[i] *= arr[d].a;
    for (int i = 0; i <= m; i++) {
        sum[i + 1] += sum[i] / 10000;
        sum[i] %= 10000;
    }
    if (sum[m + 1] != 0) m++;
}

void div(int d) {
    memset(ans, 0, sizeof(ans));
    ls = 0;
    while (m >= 0 && sum[m] == 0) m--;  // 去掉前导0
    res = 0;
    int flag = 0;
    for (int i = m; i >= 0; i--) {
        res = res * 10000 + sum[i];
        ans[++ls] = res / arr[d].b;
        if (ans[ls] == 0 && !flag) ls--;  // 不保留前导 0
        else flag = 1;
        res %= arr[d].b;
    }
}

int main() {
    cin >> n >> a >> b;
    for (int i = 0; i < n; i++) cin >> arr[i].a >> arr[i].b;
    sort(arr, arr + n);

    m = 0;
    memset(sum, 0, sizeof(sum));
    sum[0] = a;

    for (int i = 0; i < n; i++) {
        div(i);  // 先除
        if (compare()) {
            lp = ls;
            memcpy(p, ans, sizeof(ans));
        }
        cheng(i);  // 再乘
    }

    int i = 0;
    while (i <= lp && p[i] == 0) i++;  // 去前导0
    if (i > lp) {  // 全是0
        printf("0\n");
        return 0;
    }

    printf("%d", p[i++]);
    for (; i <= lp; i++) {
        printf("%04d", p[i]);  // 补足4位
    }
    printf("\n");
    return 0;
}

