int dx[5]={0,0,0,1,-1};//方便移动和处理陨石砸落
int dy[5]={0,1,-1,0,0};

int ch(int x){//判断路过该点时是否陨石已经砸落，如果是没有陨石，相当于n年后砸落
    if (x==-1) return 99999;
    else return x;
}

void sign(int i,int t)//标记陨石的下落时间
{
    if(x + dx[i] >= 0 && y + dy[i] >= 0 && (a[x + dx[i]][y + dy[i]] == -1 || a[x + dx[i]][y + dy[i]] > t))
        a[x + dx[i]][y + dy[i]] = t;
}

