    memset(a,-1,sizeof(a));//陨石砸落时间初始化
    for(int i = 1; i <= n; i++){
        cin >> x >> y >> t;
        for(int i = 0; i < 5; i ++) sign(i,t);
    }

    queue<PII> q;
    vis[0][0] = true;
    q.push({0,0});
    while(!q.empty())
    {
        int x = q.front().first,y = q.front().second;
        q.pop();
        int s = dist[x][y] + 1;//下一格子到达的时间等于当前格子加1
